import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { Cloud, Wind, Thermometer, MapPin, Navigation, Info, Zap } from "lucide-react";
import { EXOPLANETS, Exoplanet } from "./exoplanetData";

// --- Shaders ---

const skyVertexShader = `
  varying vec2 vUv;
  varying vec3 vPosition;
  void main() {
    vUv = uv;
    vPosition = position;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const skyFragmentShader = `
  uniform float uTime;
  uniform vec3 uColor;
  uniform float uTemp;
  uniform float uWindSpeed;
  uniform float uThickness;
  varying vec2 vUv;
  varying vec3 vPosition;

  float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123); }
  float noise(vec2 p) {
    vec2 i = floor(p); vec2 f = fract(p);
    vec2 u = f*f*(3.0-2.0*f);
    return mix(mix(hash(i + vec2(0,0)), hash(i + vec2(1,0)), u.x),
               mix(hash(i + vec2(0,1)), hash(i + vec2(1,1)), u.x), u.y);
  }

  void main() {
    vec2 uv = vUv;
    float phi = atan(vPosition.z, vPosition.x);
    float theta = acos(vPosition.y / length(vPosition));
    vec2 p = vec2(phi, theta);

    // Atmospheric Gradient
    vec3 skyCol = mix(uColor * 0.2, uColor, 1.0 - uv.y);
    if (uTemp > 2000.0) skyCol *= 1.5; // Brighter for hot planets

    // Clouds
    float cloudNoise = noise(p * 2.0 + uTime * uWindSpeed * 0.0001);
    cloudNoise += noise(p * 4.0 - uTime * uWindSpeed * 0.00005) * 0.5;

    float cloudMask = smoothstep(0.4, 0.6, cloudNoise * uThickness);
    skyCol = mix(skyCol, vec3(1.0), cloudMask * 0.3);

    gl_FragColor = vec4(skyCol, 1.0);
  }
`;

const surfaceFragmentShader = `
  uniform float uTime;
  uniform vec3 uColor;
  uniform int uType; // 0: Lava, 1: Ocean, 2: Gas, 3: Rock
  varying vec2 vUv;

  float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123); }
  float noise(vec2 p) {
    vec2 i = floor(p); vec2 f = fract(p);
    vec2 u = f*f*(3.0-2.0*f);
    return mix(mix(hash(i + vec2(0,0)), hash(i + vec2(1,0)), u.x),
               mix(hash(i + vec2(0,1)), hash(i + vec2(1,1)), u.x), u.y);
  }

  void main() {
    vec3 col = uColor * 0.5;

    if (uType == 0) { // Lava
        float n = noise(vUv * 10.0 + uTime * 0.5);
        col = mix(vec3(0.5, 0.1, 0.0), vec3(1.0, 0.3, 0.0), n);
    } else if (uType == 1) { // Ocean
        float n = noise(vUv * 20.0 - uTime * 0.2);
        col = mix(uColor * 0.3, uColor * 0.6, n);
    } else if (uType == 2) { // Gas
        float n = noise(vec2(vUv.x * 2.0, vUv.y * 50.0));
        col = mix(uColor * 0.4, uColor * 0.8, n);
    } else { // Rock
        float n = noise(vUv * 50.0);
        col = vec3(n * 0.2 + 0.1);
    }

    gl_FragColor = vec4(col, 1.0);
  }
`;

// --- Component ---

const ExoplanetWeather: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [currentIdx, setCurrentIdx] = useState(0);
  const planet = EXOPLANETS[currentIdx];

  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const skyMatRef = useRef<THREE.ShaderMaterial | null>(null);
  const surfMatRef = useRef<THREE.ShaderMaterial | null>(null);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color("#000000");

    const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 2000);
    camera.position.set(0, 0, 0.1);

    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    rendererRef.current = renderer;

    // --- Sky Dome ---
    const skyGeo = new THREE.SphereGeometry(1000, 64, 32);
    const skyMat = new THREE.ShaderMaterial({
      vertexShader: skyVertexShader,
      fragmentShader: skyFragmentShader,
      uniforms: {
        uTime: { value: 0 },
        uColor: { value: new THREE.Color() },
        uTemp: { value: 0 },
        uWindSpeed: { value: 0 },
        uThickness: { value: 0 }
      },
      side: THREE.BackSide
    });
    skyMatRef.current = skyMat;
    scene.add(new THREE.Mesh(skyGeo, skyMat));

    // --- Surface ---
    const surfGeo = new THREE.SphereGeometry(200, 64, 32, 0, Math.PI * 2, Math.PI * 0.5, Math.PI * 0.5);
    const surfMat = new THREE.ShaderMaterial({
      vertexShader: skyVertexShader,
      fragmentShader: surfaceFragmentShader,
      uniforms: {
        uTime: { value: 0 },
        uColor: { value: new THREE.Color() },
        uType: { value: 0 }
      }
    });
    surfMatRef.current = surfMat;
    const surface = new THREE.Mesh(surfGeo, surfMat);
    surface.position.y = -180;
    scene.add(surface);

    // --- Precipitation ---
    const rainGeo = new THREE.BufferGeometry();
    const rainCount = 5000;
    const rainPositions = new Float32Array(rainCount * 3);
    for(let i=0; i<rainCount; i++) {
        rainPositions[i*3] = (Math.random()-0.5) * 400;
        rainPositions[i*3+1] = Math.random() * 400;
        rainPositions[i*3+2] = (Math.random()-0.5) * 400;
    }
    rainGeo.setAttribute('position', new THREE.BufferAttribute(rainPositions, 3));
    const rainMat = new THREE.PointsMaterial({ size: 1, transparent: true, opacity: 0.5 });
    const rain = new THREE.Points(rainGeo, rainMat);
    scene.add(rain);

    // --- Lighting ---
    const sun = new THREE.DirectionalLight(0xffffff, 1.0);
    sun.position.set(0, 0, -1);
    scene.add(sun);

    // Animation Loop
    let animationId: number;
    const animate = (time: number) => {
      animationId = requestAnimationFrame(animate);

      const t = time * 0.001;
      skyMat.uniforms.uTime.value = time;
      surfMat.uniforms.uTime.value = t;

      // Update Rain
      const pos = rainGeo.attributes.position.array as Float32Array;
      for(let i=0; i<rainCount; i++) {
          pos[i*3+1] -= 2.0 + (planet.windSpeed / 1000);
          if(pos[i*3+1] < -50) pos[i*3+1] = 400;
      }
      rainGeo.attributes.position.needsUpdate = true;

      renderer.render(scene, camera);
    };
    animate(0);

    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(animationId);
      renderer.dispose();
    };
  }, []);

  useEffect(() => {
    if(!skyMatRef.current || !surfMatRef.current) return;

    // Update Planet Params
    const colors: Record<string, string> = {
      methane: "#00ccff",
      iron: "#ff3300",
      silicates: "#e6e6e6",
      hydrogen: "#ff99ff"
    };
    const skyColor = new THREE.Color(colors[planet.composition]);
    skyMatRef.current.uniforms.uColor.value.copy(skyColor);
    skyMatRef.current.uniforms.uTemp.value = planet.temp;
    skyMatRef.current.uniforms.uWindSpeed.value = planet.windSpeed;
    skyMatRef.current.uniforms.uThickness.value = planet.atmosphereThickness;

    surfMatRef.current.uniforms.uColor.value.copy(skyColor);
    const surfaceTypes = { lava: 0, ocean: 1, gas: 2, rock: 3 };
    surfMatRef.current.uniforms.uType.value = surfaceTypes[planet.surface];

  }, [currentIdx]);

  // Auto-Cycle
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIdx(prev => (prev + 1) % EXOPLANETS.length);
    }, 60000); // 1 minute for demo
    return () => clearInterval(timer);
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-black overflow-hidden font-mono">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Atmospheric HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-3xl font-light text-white tracking-[0.4em] uppercase">
          {planet.name}
        </h1>
        <div className="mt-4 flex flex-col space-y-2">
          <div className="flex items-center space-x-3">
             <MapPin size={14} className="text-white/40" />
             <span className="text-[10px] text-white/40 tracking-[0.2em]">{planet.distance} LY FROM EARTH</span>
          </div>
          <div className="flex items-center space-x-3">
             <Navigation size={14} className="text-white/40" />
             <span className="text-[10px] text-white/40 tracking-[0.2em] uppercase">{planet.starType}-TYPE HOST STAR</span>
          </div>
        </div>
      </div>

      {/* Weather Telemetry */}
      <div className="absolute bottom-12 left-12 z-40 p-8 rounded-3xl bg-black/40 backdrop-blur-2xl border border-white/10 text-white pointer-events-none max-w-sm">
        <div className="grid grid-cols-2 gap-8">
          <div className="flex flex-col">
            <div className="flex items-center space-x-2 mb-1">
              <Thermometer size={14} className="text-orange-500" />
              <span className="text-[9px] text-gray-500 uppercase tracking-widest">Temperature</span>
            </div>
            <span className="text-xl font-light">{planet.temp} K</span>
          </div>
          <div className="flex flex-col">
            <div className="flex items-center space-x-2 mb-1">
              <Wind size={14} className="text-blue-400" />
              <span className="text-[9px] text-gray-500 uppercase tracking-widest">Wind Velocity</span>
            </div>
            <span className="text-xl font-light">{planet.windSpeed} KM/H</span>
          </div>
          <div className="flex flex-col col-span-2">
            <div className="flex items-center space-x-2 mb-1">
              <Cloud size={14} className="text-cyan-400" />
              <span className="text-[9px] text-gray-500 uppercase tracking-widest">Atmospheric State</span>
            </div>
            <span className="text-sm font-light uppercase tracking-tighter">
              {planet.composition} rich / {planet.precipitation !== 'none' ? `${planet.precipitation} precipitation` : "stable atmospheric field"}
            </span>
          </div>
        </div>
      </div>

      {/* Navigation Buttons */}
      <div className="absolute top-10 right-10 z-40 flex space-x-2">
        {EXOPLANETS.map((p, i) => (
          <button
            key={p.name}
            onClick={() => setCurrentIdx(i)}
            className={`w-3 h-3 rounded-full transition-all ${
                currentIdx === i ? "bg-white scale-125" : "bg-white/20 hover:bg-white/40"
            }`}
          />
        ))}
      </div>

      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_200px_rgba(0,0,0,0.8)]" />
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_bottom,rgba(0,0,0,0)_0%,rgba(0,0,0,0.8)_100%)]" />
    </div>
  );
};

