import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { RefreshCw, Pause, Play, ShieldCheck, Wind } from "lucide-react";
import { analyzeText, EmotionalState } from "./emotionEngine";

// --- GLSL Shaders ---

const terrainVertexShader = `
  varying vec2 vUv;
  varying float vHeight;
  uniform float uTime;
  uniform float uRoughness;
  uniform float uEvolution;

  // 2D Noise
  vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
  float snoise(vec2 v){
    const vec4 C = vec4(0.211324865405187, 0.366025403784439,
             -0.577350269189626, 0.024390243902439);
    vec2 i  = floor(v + dot(v, C.yy) );
    vec2 x0 = v -   i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.xy -= i1;
    i = mod(i, 289.0);
    vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
    + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy),
      dot(x12.zw,x12.zw)), 0.0);
    m = m*m ;
    m = m*m ;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 a0 = x - floor(x + 0.5);
    vec3 g = a0.x  * vec2(x0.x,x12.x) + h.x  * vec2(x0.y,x12.y);
    float n = 130.0 * dot(m, g);
    return n;
  }

  void main() {
    vUv = uv;

    // Multi-layered noise
    float n1 = snoise(uv * 1.5 + uEvolution * 0.05) * 1.0;
    float n2 = snoise(uv * 4.0 + uEvolution * 0.1) * 0.4;
    float n3 = snoise(uv * 8.0 + uEvolution * 0.2) * 0.15;

    float height = n1 + n2 + n3;
    height *= uRoughness * 4.0;
    vHeight = height;

    vec3 pos = position;
    pos.z += height;

    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const terrainFragmentShader = `
  varying vec2 vUv;
  varying float vHeight;
  uniform vec3 uColorLow;
  uniform vec3 uColorHigh;
  uniform float uFogDensity;
  uniform vec3 uFogColor;

  void main() {
    // Base color from height
    float h = clamp(vHeight * 0.2 + 0.5, 0.0, 1.0);
    vec3 color = mix(uColorLow, uColorHigh, h);

    // Simple top-down lighting
    color *= (0.8 + 0.2 * sin(vHeight * 2.0));

    // Fog
    float depth = gl_FragCoord.z / gl_FragCoord.w;
    float fogFactor = exp2(-uFogDensity * uFogDensity * depth * depth * 1.442695);
    fogFactor = clamp(fogFactor, 0.0, 1.0);

    gl_FragColor = vec4(mix(uFogColor, color, fogFactor), 1.0);
  }
`;

// --- Component ---

const GriefCartographer: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [inputText, setInputText] = useState("");
  const [isSimulating, setIsSimulating] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  // Refs for Three.js
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const uniformsRef = useRef<any>({
    uTime: { value: 0 },
    uEvolution: { value: Math.random() * 100 },
    uRoughness: { value: 0.2 },
    uColorLow: { value: new THREE.Color("#1a1a2e") },
    uColorHigh: { value: new THREE.Color("#4e4e6d") },
    uFogDensity: { value: 0.05 },
    uFogColor: { value: new THREE.Color("#050505") },
  });

  const [emotionalState, setEmotionalState] = useState<EmotionalState>({
    intensity: 0.2,
    recency: 0.2,
    ambivalence: 0.1,
    gratitude: 0.3
  });

  const startCartography = () => {
    const state = analyzeText(inputText);
    setEmotionalState(state);
    setIsSimulating(true);
  };

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current || !isSimulating) return;

    // Initialize Scene
    const scene = new THREE.Scene();
    scene.background = uniformsRef.current.uFogColor.value;

    const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.set(0, -10, 4);
    camera.lookAt(0, 5, 0);

    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    rendererRef.current = renderer;

    // Terrain
    const geometry = new THREE.PlaneGeometry(30, 30, 200, 200);
    const material = new THREE.ShaderMaterial({
      vertexShader: terrainVertexShader,
      fragmentShader: terrainFragmentShader,
      uniforms: uniformsRef.current,
      side: THREE.DoubleSide,
    });
    const terrain = new THREE.Mesh(geometry, material);
    scene.add(terrain);

    // Weather particles (subtle storm)
    const particleCount = 1000;
    const pGeometry = new THREE.BufferGeometry();
    const pPositions = new Float32Array(particleCount * 3);
    for (let i = 0; i < particleCount; i++) {
      pPositions[i * 3] = (Math.random() - 0.5) * 40;
      pPositions[i * 3 + 1] = (Math.random() - 0.5) * 40;
      pPositions[i * 3 + 2] = Math.random() * 10;
    }
    pGeometry.setAttribute('position', new THREE.BufferAttribute(pPositions, 3));
    const pMaterial = new THREE.PointsMaterial({
      color: "#ffffff",
      size: 0.02,
      transparent: true,
      opacity: 0.2,
    });
    const particles = new THREE.Points(pGeometry, pMaterial);
    scene.add(particles);

    // Update colors based on gratitude
    const updateColors = (state: EmotionalState) => {
      const g = state.gratitude;
      const i = state.intensity;

      // Roughness -> Intensity
      uniformsRef.current.uRoughness.target = 0.1 + i * 0.8;

      // Gratitude -> Warmth
      const warmLow = new THREE.Color("#2d1a0a"); // Warm brown
      const warmHigh = new THREE.Color("#d4a373"); // Golden
      const coldLow = new THREE.Color("#0a1a2d"); // Cold blue
      const coldHigh = new THREE.Color("#a2d2ff"); // Pale blue

      uniformsRef.current.uColorLow.target = new THREE.Color().copy(coldLow).lerp(warmLow, g);
      uniformsRef.current.uColorHigh.target = new THREE.Color().copy(coldHigh).lerp(warmHigh, g);

      // Recency -> Fog/Storm
      uniformsRef.current.uFogDensity.target = 0.02 + state.recency * 0.08;
      pMaterial.opacity = 0.05 + state.recency * 0.3;
    };

    updateColors(emotionalState);

    // Animation loop
    let animationId: number;
    const lerp = (a: number, b: number, t: number) => a + (b - a) * t;
    const lerpColor = (c1: THREE.Color, c2: THREE.Color, t: number) => c1.lerp(c2, t);

    const animate = (time: number) => {
      animationId = requestAnimationFrame(animate);
      if (isPaused) return;

      const dt = 0.01;
      uniformsRef.current.uTime.value = time * 0.001;
      uniformsRef.current.uEvolution.value += 0.002 * (1.0 + emotionalState.recency);

      // Smooth updates
      if (uniformsRef.current.uRoughness.target !== undefined) {
        uniformsRef.current.uRoughness.value = lerp(uniformsRef.current.uRoughness.value, uniformsRef.current.uRoughness.target, dt);
        uniformsRef.current.uFogDensity.value = lerp(uniformsRef.current.uFogDensity.value, uniformsRef.current.uFogDensity.target, dt);
        lerpColor(uniformsRef.current.uColorLow.value, uniformsRef.current.uColorLow.target, dt);
        lerpColor(uniformsRef.current.uColorHigh.value, uniformsRef.current.uColorHigh.target, dt);
      }

      // Ambivalence -> Shifting Light
      const lightShift = Math.sin(time * 0.001 * (1.0 + emotionalState.ambivalence)) * 0.2;
      uniformsRef.current.uColorHigh.value.offsetHSL(0, 0, lightShift * emotionalState.ambivalence);

      // Move particles
      const positions = pGeometry.attributes.position.array as Float32Array;
      for (let i = 0; i < particleCount; i++) {
        positions[i * 3 + 2] -= 0.05 * (1.0 + emotionalState.recency);
        if (positions[i * 3 + 2] < 0) positions[i * 3 + 2] = 10;
      }
      pGeometry.attributes.position.needsUpdate = true;

      // Subtle camera sway
      camera.position.x = Math.sin(time * 0.0002) * 2;
      camera.lookAt(0, 5, 0);

      renderer.render(scene, camera);
    };

    animate(0);

    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(animationId);
      geometry.dispose();
      material.dispose();
      renderer.dispose();
    };
  }, [isSimulating, emotionalState]); // Re-init only when starting or changing state significantly

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-[#050505] overflow-hidden">
      {!isSimulating ? (
        <div className="absolute inset-0 flex items-center justify-center z-20 px-4">
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="w-full max-w-xl p-10 rounded-3xl bg-white/[0.02] border border-white/10 backdrop-blur-2xl text-center"
          >
            <h1 className="text-3xl font-light text-white mb-6 tracking-tight">The Grief Cartographer</h1>
            <p className="text-gray-400 text-sm mb-8 leading-relaxed">
              Translate your unspoken thoughts into a living landscape.<br/>
              Your words stay on this device.
            </p>

            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="What weighs on you today? (Optional)"
              className="w-full h-32 bg-black/40 border border-white/10 rounded-2xl p-4 text-white placeholder:text-gray-600 focus:outline-none focus:border-purple-500/50 transition-colors mb-6 resize-none"
            />

            <button
              onClick={startCartography}
