// --- Texture Generator ---
const generateNoiseTexture = (size: number = 1024) => {
  const canvas = document.createElement("canvas");
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext("2d")!;

  const imgData = ctx.createImageData(size, size);
  for (let i = 0; i < imgData.data.length; i += 4) {
    const v = Math.random() * 255;
    imgData.data[i] = v;
    imgData.data[i+1] = v;
    imgData.data[i+2] = v;
    imgData.data[i+3] = 255;
  }
  ctx.putImageData(imgData, 0, 0);

  const tex = new THREE.CanvasTexture(canvas);
  tex.wrapS = tex.wrapT = THREE.RepeatWrapping;
  return tex;
};

// --- Component ---

const HapticMemory: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [currentIdx, setCurrentIdx] = useState(0);
  const material = MATERIAL_LIBRARY[currentIdx];

  const [userInput, setUserInput] = useState("");
  const [isOverlayVisible, setIsOverlayVisible] = useState(true);

  // Three.js Refs
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const materialRef = useRef<THREE.MeshStandardMaterial | null>(null);
  const lightRef = useRef<THREE.DirectionalLight | null>(null);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color("#050508");

    const camera = new THREE.PerspectiveCamera(35, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.set(0, 5, 8);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    rendererRef.current = renderer;

    // --- Lighting (Raking Light) ---
    const ambient = new THREE.AmbientLight(0xffffff, 0.05);
    scene.add(ambient);

    const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
    dirLight.position.set(10, 1, 0); // Low angle
    dirLight.castShadow = true;
    scene.add(dirLight);
    lightRef.current = dirLight;

    // --- Surface ---
    const noiseTex = generateNoiseTexture();
    const mat = new THREE.MeshStandardMaterial({
      color: material.config.color,
      roughness: material.config.roughness,
      metalness: material.config.metalness,
      normalMap: noiseTex,
      normalScale: new THREE.Vector2(material.config.normalScale, material.config.normalScale),
      bumpMap: noiseTex,
      bumpScale: material.config.bumpScale,
    });
    materialRef.current = mat;

    const geo = new THREE.PlaneGeometry(20, 20, 128, 128);
    const plane = new THREE.Mesh(geo, mat);
    plane.rotation.x = -Math.PI / 2;
    scene.add(plane);

    // Animation Loop
    let animationId: number;
    const animate = (time: number) => {
      animationId = requestAnimationFrame(animate);

      const t = time * 0.0005;
      // Slow Orbit of light
      if (lightRef.current) {
        lightRef.current.position.x = Math.cos(t * 0.2) * 10;
        lightRef.current.position.z = Math.sin(t * 0.2) * 10;
        lightRef.current.position.y = 1 + Math.sin(t * 0.5) * 0.5; // Slight altitude wobble
      }

      renderer.render(scene, camera);
    };
    animate(0);

    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(animationId);
      renderer.dispose();
      noiseTex.dispose();
    };
  }, []);

  useEffect(() => {
    if (!materialRef.current) return;

    // Smooth transition (Manual lerp or just set)
    const mat = materialRef.current;
    mat.color.set(material.config.color);
    mat.roughness = material.config.roughness;
    mat.metalness = material.config.metalness;
    mat.normalScale.set(material.config.normalScale, material.config.normalScale);
    mat.bumpScale = material.config.bumpScale;
  }, [currentIdx]);

  // Auto-Cycle
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIdx(prev => (prev + 1) % MATERIAL_LIBRARY.length);
    }, 45000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-[#050508] overflow-hidden">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Atmospheric HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-xl font-light text-white/20 tracking-[0.6em] uppercase">
          Haptic Memory Theatre
        </h1>
        <div className="flex items-center space-x-3 mt-2">
           <Hand size={12} className="text-amber-500/50 animate-pulse" />
           <span className="text-[10px] text-white/10 font-mono tracking-widest uppercase">
             Sensory Reconstruction Active
           </span>
        </div>
      </div>

      {/* Material Inscription */}
      <AnimatePresence mode="wait">
        <motion.div
            key={material.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 2 }}
            className="absolute bottom-20 left-20 z-40 max-w-lg pointer-events-none"
        >
            <span className="text-[10px] text-amber-500/60 uppercase tracking-[0.4em] block mb-4">
                Memory Surface {currentIdx + 1} // {material.emotion}
            </span>
            <h2 className="text-4xl font-light text-white mb-6 uppercase tracking-tight">
                {material.name}
            </h2>
            <p className="text-xl font-light text-white/40 leading-relaxed italic border-l border-white/10 pl-8">
                "{material.description}"
            </p>
        </motion.div>
      </AnimatePresence>

      {/* Memory Input */}
      <div className="absolute top-10 right-10 z-40 flex flex-col items-end">
        <div className="relative group">
            <input 
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
