                className="bg-transparent border-b border-white/10 py-2 px-4 text-[10px] text-white tracking-[0.3em] uppercase focus:outline-none focus:border-amber-500/50 transition-all w-64 text-right"
            />
            <MessageSquare size={14} className="absolute right-0 -top-4 text-white/20 group-hover:text-amber-500 transition-colors" />
        </div>
      </div>

      <div className="absolute bottom-10 right-10 z-40 text-[9px] text-white/5 uppercase tracking-[0.3em] text-right max-w-xs italic leading-relaxed">
        "Touching the past through the geometry of shadow."
