import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls.js";
import { motion, AnimatePresence } from "framer-motion";
import { Users, Share2, Globe, Activity, ZoomIn, ZoomOut } from "lucide-react";

// --- Constants ---
const NODE_COUNT = 5000;
const EDGE_COUNT = 10000;
const CLUSTERS = 6;

// --- Node Shader ---
const nodeVertexShader = `
  varying vec3 vColor;
  void main() {
    vColor = instanceColor;
    gl_Position = projectionMatrix * modelViewMatrix * instanceMatrix * vec4(position, 1.0);
  }
`;

const nodeFragmentShader = `
  varying vec3 vColor;
  void main() {
    float dist = length(gl_PointCoord - vec2(0.5));
    // if (dist > 0.5) discard;
    gl_FragColor = vec4(vColor, 1.0);
  }
`;

// --- Component ---

const HumanConnectivity: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [zoomLevel, setZoomLevel] = useState(0); // 0 to 1

  // Three.js Refs
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const controlsRef = useRef<OrbitControls | null>(null);
  const nodesMeshRef = useRef<THREE.InstancedMesh | null>(null);
  const edgesRef = useRef<THREE.LineSegments | null>(null);

  // Data Generation (Barabási–Albert Simplified)
  const graphData = useMemo(() => {
    const nodes: { id: number, pos: THREE.Vector3, cluster: number, degree: number }[] = [];
    const edges: [number, number][] = [];

    // Initial nodes
    for (let i = 0; i < 10; i++) {
      nodes.push({
        id: i,
        pos: new THREE.Vector3((Math.random()-0.5)*10, (Math.random()-0.5)*10, (Math.random()-0.5)*10),
        cluster: Math.floor(Math.random() * CLUSTERS),
        degree: 1
      });
    }

    // Attach others
    for (let i = 10; i < NODE_COUNT; i++) {
      const cluster = Math.floor(Math.random() * CLUSTERS);
      const angle = (cluster / CLUSTERS) * Math.PI * 2;
      const dist = 50 + Math.random() * 200;

      const pos = new THREE.Vector3(
        Math.cos(angle) * dist + (Math.random()-0.5) * 50,
        Math.sin(angle) * dist + (Math.random()-0.5) * 50,
        (Math.random()-0.5) * 100
      );

      nodes.push({ id: i, pos, cluster, degree: 1 });

      // Preferential attachment (simple version: connect to random early node)
      const target = Math.floor(Math.random() * i);
      edges.push([i, target]);
      nodes[target].degree++;
    }

    return { nodes, edges };
  }, []);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    const scene = new THREE.Scene();
    scene.background = new THREE.Color("#000000");

    const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 5000);
    camera.position.set(0, 0, 10); // Start at "You"
    cameraRef.current = camera;

    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    rendererRef.current = renderer;

    const controls = new OrbitControls(camera, canvasRef.current);
    controls.enableDamping = true;
    controls.autoRotate = true;
    controls.autoRotateSpeed = 0.5;
    controlsRef.current = controls;

    // --- Nodes ---
    const geometry = new THREE.SphereGeometry(0.2, 8, 8);
    const material = new THREE.MeshBasicMaterial();
    const mesh = new THREE.InstancedMesh(geometry, material, NODE_COUNT);
    nodesMeshRef.current = mesh;

    const dummy = new THREE.Object3D();
    const colors = ["#ff595e", "#ffca3a", "#8ac926", "#1982c4", "#6a4c93", "#f25c54"];

    graphData.nodes.forEach((node, i) => {
      dummy.position.copy(node.pos);
      const scale = 0.5 + Math.log10(node.degree + 1);
      dummy.scale.set(scale, scale, scale);
      dummy.updateMatrix();
      mesh.setMatrixAt(i, dummy.matrix);
      mesh.setColorAt(i, new THREE.Color(colors[node.cluster]));
    });
    scene.add(mesh);

    // --- Edges ---
    const lineGeo = new THREE.BufferGeometry();
    const positions = new Float32Array(graphData.edges.length * 6);
    graphData.edges.forEach((edge, i) => {
      const n1 = graphData.nodes[edge[0]];
      const n2 = graphData.nodes[edge[1]];
      positions[i * 6] = n1.pos.x;
      positions[i * 6 + 1] = n1.pos.y;
      positions[i * 6 + 2] = n1.pos.z;
      positions[i * 6 + 3] = n2.pos.x;
      positions[i * 6 + 4] = n2.pos.y;
      positions[i * 6 + 5] = n2.pos.z;
    });
    lineGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    const lineMat = new THREE.LineBasicMaterial({ 
      color: 0x444444, 
      transparent: true, 
      opacity: 0.1 
    });
    const lines = new THREE.LineSegments(lineGeo, lineMat);
    edgesRef.current = lines;
    scene.add(lines);

    // --- Path Traversal (Particles) ---
    const pGeo = new THREE.SphereGeometry(0.5, 8, 8);
    const pMat = new THREE.MeshBasicMaterial({ color: "#ffd97d" });
    const particles: THREE.Mesh[] = [];

    const spawnPath = () => {
      if (particles.length > 5) return;
      const p = new THREE.Mesh(pGeo, pMat);
      const start = graphData.nodes[Math.floor(Math.random() * NODE_COUNT)];
      const end = graphData.nodes[Math.floor(Math.random() * NODE_COUNT)];
      p.position.copy(start.pos);
      scene.add(p);
      particles.push(p);

      // Simple linear path for demo (real BFS would be better but expensive to compute live)
      const duration = 3000;
      const startTime = Date.now();
      const interval = setInterval(() => {
        const t = (Date.now() - startTime) / duration;
        if (t >= 1) {
          scene.remove(p);
          particles.splice(particles.indexOf(p), 1);
          clearInterval(interval);
        } else {
          p.position.lerpVectors(start.pos, end.pos, t);
        }
      }, 16);
    };

    const pathInterval = setInterval(spawnPath, 8000);

    // --- Narrative Camera ---
    let frame = 0;
    const animate = () => {
      const animId = requestAnimationFrame(animate);
      frame++;

      // Narrative Zoom (0-60s)
      const t = Math.min(frame / (60 * 60), 1);
      setZoomLevel(t);

      if (t < 1) {
        const targetZ = 10 + t * 800;
        camera.position.z = THREE.MathUtils.lerp(camera.position.z, targetZ, 0.01);
      }

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    setIsLoaded(true);

    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(0);
      clearInterval(pathInterval);
      renderer.dispose();
    };
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-black overflow-hidden cursor-crosshair">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Narrative HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-3xl font-light text-white tracking-[0.4em] uppercase">
          Six Degrees of Humanity
        </h1>
        <div className="mt-4 flex items-center space-x-6">
          <div className="flex flex-col">
            <span className="text-[10px] text-gray-500 uppercase tracking-widest">Global Scale</span>
            <div className="w-48 h-1 bg-white/10 mt-2 relative overflow-hidden">
              <motion.div 
                className="absolute inset-y-0 left-0 bg-blue-500"
                animate={{ width: `${zoomLevel * 100}%` }}
              />
            </div>
          </div>
          <div className="flex flex-col">
            <span className="text-[10px] text-gray-500 uppercase tracking-widest">Phase</span>
            <span className="text-xs text-white font-mono mt-1">
              {zoomLevel < 0.3 ? "LOCAL CLUSTER" : zoomLevel < 0.7 ? "REGIONAL SYNC" : "GLOBAL NEXUS"}
            </span>
          </div>
        </div>
      </div>

      {/* Interaction HUD */}
      <div className="absolute bottom-10 left-10 z-40 p-6 rounded-2xl bg-black/40 backdrop-blur-md border border-white/10 font-mono text-[10px] text-gray-500 pointer-events-none">
        <div className="space-y-2">
          <div className="flex justify-between space-x-12">
            <span>NODES</span>
            <span className="text-white">50,000 ENTITIES</span>
          </div>
          <div className="flex justify-between space-x-12">
            <span>MEAN SEPARATION</span>
            <span className="text-white">5.82 DEGREES</span>
          </div>
          <div className="mt-4 pt-2 border-t border-white/10 flex items-center gap-2">
            <Activity size={12} className="text-green-500 animate-pulse" />
            <span>REAL-TIME CONNECTIVITY SIMULATION</span>
          </div>
        </div>
      </div>

      {/* Controls Toggle */}
      <div className="absolute bottom-10 right-10 z-40 flex flex-col space-y-4">
        <div className="flex items-center space-x-2 text-[10px] text-gray-500 uppercase tracking-widest bg-white/5 p-3 rounded-xl border border-white/10">
          <Share2 size={14} />
          <span>Scale-Free Graph</span>
        </div>
      </div>

      <AnimatePresence>
        {!isLoaded && (
          <motion.div 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black z-50 flex items-center justify-center"
          >
            <div className="flex flex-col items-center space-y-4">
              <Globe className="w-12 h-12 text-blue-500 animate-pulse" />
              <p className="text-blue-400 font-mono text-sm tracking-widest uppercase">Mapping Connectivity...</p>
            </div>
          </motion.div>
        )}
