import React, { useEffect, useRef, useState, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Activity, Globe, Database, Zap, ShieldAlert, Navigation, Info } from "lucide-react";
import { IXP_NODES, SUBSEA_CABLES, IXPNode, SubseaCable } from "./infrastructure";

// --- Projection ---
const project = (lat: number, lng: number, width: number, height: number) => {
  const x = ((lng + 180) * width) / 360;
  const y = ((90 - lat) * height) / 180;
  return { x, y };
};

// --- Component ---

const InternetHeartbeat: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [dims, setDims] = useState({ width: 1200, height: 600 });
  const [selectedCable, setSelectedCable] = useState<SubseaCable | null>(null);
  const [selectedNode, setSelectedNode] = useState<IXPNode | null>(null);
  const [bgpEvents, setBgpEvents] = useState<{ id: string, x: number, y: number }[]>([]);

  useEffect(() => {
    const updateDims = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight
        });
      }
    };
    updateDims();
    window.addEventListener("resize", updateDims);
    return () => window.removeEventListener("resize", updateDims);
  }, []);

  // --- Particle System (Canvas) ---
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let frame = 0;
    const particles: { cableId: string, progress: number, speed: number, size: number }[] = [];

    const animate = () => {
      frame++;
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Spawn particles
      if (frame % 5 === 0) {
        const cable = SUBSEA_CABLES[Math.floor(Math.random() * SUBSEA_CABLES.length)];
        particles.push({
          cableId: cable.id,
          progress: 0,
          speed: 0.002 + cable.load * 0.005,
          size: 1 + Math.random() * 2
        });
      }

      // Update & Draw
      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.progress += p.speed;

        if (p.progress >= 1) {
          particles.splice(i, 1);
          continue;
        }

        const cable = SUBSEA_CABLES.find(c => c.id === p.cableId)!;
        const n1 = IXP_NODES.find(n => n.id === cable.nodes[0])!;
        const n2 = IXP_NODES.find(n => n.id === cable.nodes[1])!;

        const p1 = project(n1.lat, n1.lng, canvas.width, canvas.height);
        const p2 = project(n2.lat, n2.lng, canvas.width, canvas.height);

        // Quadratic Curve Logic (Simple lerp for now, or actual curve)
        const midX = (p1.x + p2.x) / 2;
        const midY = (p1.y + p2.y) / 2 - Math.abs(p1.x - p2.x) * 0.2;

        const t = p.progress;
        const cx = (1 - t) * (1 - t) * p1.x + 2 * (1 - t) * t * midX + t * t * p2.x;
        const cy = (1 - t) * (1 - t) * p1.y + 2 * (1 - t) * t * midY + t * t * p2.y;

        ctx.fillStyle = "#4fd1c5"; // Teal
        ctx.globalAlpha = 0.6 * (1 - Math.abs(p.progress - 0.5) * 2);
        ctx.beginPath();
        ctx.arc(cx, cy, p.size, 0, Math.PI * 2);
        ctx.fill();
      }

      requestAnimationFrame(animate);
    };

    const animId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animId);
  }, [dims]);

  // --- Random BGP Events ---
  useEffect(() => {
    const interval = setInterval(() => {
      const node = IXP_NODES[Math.floor(Math.random() * IXP_NODES.length)];
      const { x, y } = project(node.lat, node.lng, dims.width, dims.height);
      const id = Math.random().toString();
      setBgpEvents(prev => [...prev, { id, x, y }]);
      setTimeout(() => setBgpEvents(prev => prev.filter(e => e.id !== id)), 2000);
    }, 3000);
    return () => clearInterval(interval);
  }, [dims]);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-[#050508] overflow-hidden">
      {/* Background World Map SVG */}
      <svg className="absolute inset-0 w-full h-full opacity-5 pointer-events-none" viewBox={`0 0 ${dims.width} ${dims.height}`}>
         <text x="50%" y="50%" className="fill-white text-[150px] uppercase font-bold" style={{ textAnchor: 'middle' }}>NETWORK</text>
      </svg>

      {/* Cables Layer (SVG) */}
      <svg className="absolute inset-0 w-full h-full z-10" viewBox={`0 0 ${dims.width} ${dims.height}`}>
        {SUBSEA_CABLES.map(cable => {
            const n1 = IXP_NODES.find(n => n.id === cable.nodes[0])!;
            const n2 = IXP_NODES.find(n => n.id === cable.nodes[1])!;
            const p1 = project(n1.lat, n1.lng, dims.width, dims.height);
            const p2 = project(n2.lat, n2.lng, dims.width, dims.height);
            const midX = (p1.x + p2.x) / 2;
            const midY = (p1.y + p2.y) / 2 - Math.abs(p1.x - p2.x) * 0.2;

            return (
                <path 
                    key={cable.id}
                    d={`M ${p1.x} ${p1.y} Q ${midX} ${midY} ${p2.x} ${p2.y}`}
                    fill="none"
                    stroke={selectedCable?.id === cable.id ? "#fff" : "#1a3a3a"}
                    strokeWidth={1 + cable.load * 2}
                    className="cursor-pointer transition-all duration-500"
                    onClick={() => { setSelectedCable(cable); setSelectedNode(null); }}
                />
            );
        })}

        {/* IXP Nodes */}
        {IXP_NODES.map(node => {
            const { x, y } = project(node.lat, node.lng, dims.width, dims.height);
            return (
                <g key={node.id} className="cursor-pointer" onClick={() => { setSelectedNode(node); setSelectedCable(null); }}>
                    <circle 
                        cx={x} cy={y} r={node.throughput / 500} 
                        fill="#f6ad55" className="opacity-20 animate-pulse" 
                    />
                    <circle cx={x} cy={y} r="2" fill="#f6ad55" />
                </g>
            );
        })}
      </svg>

      {/* Particles Layer (Canvas) */}
      <canvas 
        ref={canvasRef}
        width={dims.width}
        height={dims.height}
        className="absolute inset-0 z-20 pointer-events-none"
      />

      {/* BGP Flashes */}
      <div className="absolute inset-0 pointer-events-none z-30">
        <AnimatePresence>
            {bgpEvents.map(e => (
                <motion.div
                    key={e.id}
                    initial={{ scale: 0, opacity: 1 }}
                    animate={{ scale: 4, opacity: 0 }}
                    exit={{ opacity: 0 }}
                    className="absolute w-4 h-4 bg-red-500 rounded-full blur-md"
                    style={{ left: e.x - 8, top: e.y - 8 }}
                />
            ))}
        </AnimatePresence>
      </div>

      {/* HUD Info */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-xl font-light text-white/40 tracking-[0.5em] uppercase">
          Internet Heartbeat
        </h1>
        <div className="flex items-center space-x-3 mt-2">
           <Activity size={12} className="text-teal-500/50 animate-pulse" />
           <span className="text-[10px] text-white/10 font-mono tracking-widest uppercase">
             Global Traffic Ingest Active
           </span>
        </div>
      </div>

      <AnimatePresence>
        {(selectedCable || selectedNode) && (
            <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="absolute top-1/2 left-10 -translate-y-1/2 w-80 z-40 p-8 bg-black/80 border border-white/10 backdrop-blur-2xl rounded-sm"
            >
                <button onClick={() => { setSelectedCable(null); setSelectedNode(null); }} className="absolute top-4 right-4 text-white/20 hover:text-white">×</button>
                {selectedCable ? (
                    <>
                        <h2 className="text-sm font-bold text-teal-400 mb-2 uppercase tracking-[0.2em]">Subsea Infrastructure</h2>
                        <p className="text-2xl font-light text-white mb-4 uppercase tracking-tighter">{selectedCable.name}</p>
                        <div className="space-y-3 text-[10px] text-gray-500 uppercase tracking-widest">
