const N = 2000;
const MAX_CONNS = 60; // Max connections per neuron (~3% density)

// State arrays
const potentials = new Float32Array(N);
const thresholds = new Float32Array(N).fill(1.0);
const refractory = new Int32Array(N);
const types = new Int8Array(N); // 1 for excitatory, -1 for inhibitory

// Connection data
const connections = new Int32Array(N * MAX_CONNS).fill(-1);
const weights = new Float32Array(N * MAX_CONNS);

let state = "DEFAULT";
const params = {
  leak: 0.02,
  noise: 0.005,
  inhibition: 1.0,
  speed: 1.0,
};

// Transmission delay queue
const delays: { target: number; weight: number; time: number }[] = [];

function init() {
  for (let i = 0; i < N; i++) {
    // 80% excitatory, 20% inhibitory
    types[i] = Math.random() > 0.2 ? 1 : -1;

    // Random sparse connections
    for (let j = 0; j < MAX_CONNS; j++) {
      if (Math.random() < 0.8) {
        const target = Math.floor(Math.random() * N);
        if (target !== i) {
          connections[i * MAX_CONNS + j] = target;
          // Weights: excitatory is positive, inhibitory is negative
          weights[i * MAX_CONNS + j] = types[i] * (0.1 + Math.random() * 0.2);
        }
      }
    }
  }
}

init();

function update(externalStimulus: Float32Array, currentTime: number) {
  const fired = new Uint8Array(N);

  // Update state-specific params
  let currentLeak = params.leak;
  let currentNoise = params.noise;
  let currentInhibition = params.inhibition;

  if (state === "FOCUS") {
    currentInhibition = 1.8;
    currentNoise = 0.002;
  } else if (state === "SLEEP") {
    // Slow wave oscillation (1-2 Hz)
    const wave = Math.sin(currentTime * 0.005) * 0.5 + 0.5;
    currentNoise = 0.001 + wave * 0.02;
    currentLeak = 0.01;
  } else if (state === "CREATIVE") {
    currentInhibition = 0.6;
    currentNoise = 0.015;
  }

  // Global inhibition pool
  let totalFiring = 0;

  // Process delays
  for (let i = delays.length - 1; i >= 0; i--) {
    if (delays[i].time <= currentTime) {
      potentials[delays[i].target] += delays[i].weight;
      delays.splice(i, 1);
    }
  }

  for (let i = 0; i < N; i++) {
    if (refractory[i] > 0) {
      refractory[i]--;
      potentials[i] = 0;
      continue;
    }

    // Apply leak
    potentials[i] *= (1.0 - currentLeak);

    // Apply noise
    potentials[i] += (Math.random() - 0.5) * currentNoise;

    // Apply external stimulus (mouse)
    potentials[i] += externalStimulus[i];

    // Global inhibition scaling
    if (types[i] === -1) {
      // Inhibitory neurons are more active if network is over-excited
      potentials[i] += totalFiring * 0.05;
    }

    // Check for spike
    if (potentials[i] >= thresholds[i]) {
      fired[i] = 1;
      potentials[i] = 0;
      refractory[i] = 5; // 5 steps refractory
      totalFiring++;

      // Send signals to neighbors
      for (let j = 0; j < MAX_CONNS; j++) {
        const target = connections[i * MAX_CONNS + j];
        if (target === -1) break;

        let weight = weights[i * MAX_CONNS + j];
        if (types[i] === -1) weight *= currentInhibition;

        delays.push({
          target,
          weight,
          time: currentTime + 1 + Math.floor(Math.random() * 3)
        });
      }
    }
  }

  return { potentials, fired };
}

self.onmessage = (e) => {
  const { action, data, time } = e.data;
  if (action === "update") {
    const result = update(data.stimulus, time);
    // @ts-ignore
    self.postMessage({ action: "render", potentials: result.potentials, fired: result.fired }, [result.potentials.buffer, result.fired.buffer]);
  } else if (action === "setState") {
    state = data.state;
  }
};

import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { Brain, Zap, Moon, Lightbulb, Activity } from "lucide-react";

// --- Types ---
type BrainState = "DEFAULT" | "FOCUS" | "SLEEP" | "CREATIVE";

const N = 2000;

const NeuralFirestorm: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [brainState, setBrainState] = useState<BrainState>("DEFAULT");
  const [isLoaded, setIsLoaded] = useState(false);

  // Refs for simulation and rendering
  const workerRef = useRef<Worker | null>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const instancedMeshRef = useRef<THREE.InstancedMesh | null>(null);
  const mouseRef = useRef(new THREE.Vector2(-10, -10));

  // Buffers for simulation
  const stimulusBuffer = useRef(new Float32Array(N));
  const neuronPositions = useMemo(() => {
    const pos = new Float32Array(N * 3);
    for (let i = 0; i < N; i++) {
      // Create a brain-like shape (ellipsoid/lobed)
      const phi = Math.acos(-1 + (2 * i) / N);
      const theta = Math.sqrt(N * Math.PI) * phi;

      const r = 4 + Math.random() * 0.5;
      const x = r * Math.sin(phi) * Math.cos(theta);
      const y = r * Math.sin(phi) * Math.sin(theta) * 0.6; // Flattened
      const z = r * Math.cos(phi) * 1.2; // Elongated

      pos[i * 3] = x;
      pos[i * 3 + 1] = y;
      pos[i * 3 + 2] = z;
    }
    return pos;
  }, []);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    // --- Initialize Three.js ---
    const scene = new THREE.Scene();
    scene.background = new THREE.Color("#05050a");
    sceneRef.current = scene;

    const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.z = 15;
    cameraRef.current = camera;

    const renderer = new THREE.WebGLRenderer({
      canvas: canvasRef.current,
      antialias: true,
      powerPreference: "high-performance",
    });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    rendererRef.current = renderer;

    // --- Instanced Mesh for Neurons ---
    const geometry = new THREE.CircleGeometry(0.06, 8);
    const material = new THREE.MeshBasicMaterial({ 
      transparent: true,
      opacity: 0.8,
      blending: THREE.AdditiveBlending
    });
    const mesh = new THREE.InstancedMesh(geometry, material, N);

    const dummy = new THREE.Object3D();
    for (let i = 0; i < N; i++) {
      dummy.position.set(neuronPositions[i*3], neuronPositions[i*3+1], neuronPositions[i*3+2]);
      dummy.updateMatrix();
      mesh.setMatrixAt(i, dummy.matrix);
      mesh.setColorAt(i, new THREE.Color("#2a1b4d")); // Default resting color
    }
    scene.add(mesh);
    instancedMeshRef.current = mesh;

    // --- Web Worker Setup ---
    // Note: In a real Vite project, we use ?worker. 
    // Here we'll create it via blob for maximum portability or assume URL works.
    const worker = new Worker(new URL("./NeuralSimulation.worker.ts", import.meta.url), { type: 'module' });
    workerRef.current = worker;

    const restingColor = new THREE.Color("#2a1b4d");
    const firingColor = new THREE.Color("#ffcc33");

    worker.onmessage = (e) => {
      const { action, potentials, fired } = e.data;
      if (action === "render") {
        for (let i = 0; i < N; i++) {
          if (fired[i]) {
            mesh.setColorAt(i, firingColor);
          } else {
            // Fade back to resting color
            const currentColor = new THREE.Color();
            mesh.getColorAt(i, currentColor);
            currentColor.lerp(restingColor, 0.1);
            mesh.setColorAt(i, currentColor);
          }
        }
        mesh.instanceColor!.needsUpdate = true;

        // Next update
        requestUpdate();
      }
    };

    const requestUpdate = () => {
      // Calculate stimulus from mouse
      const stimulus = stimulusBuffer.current;
      stimulus.fill(0);

      const raycaster = new THREE.Raycaster();
      raycaster.setFromCamera(mouseRef.current, camera);
      const intersects = raycaster.intersectObject(mesh);

      if (intersects.length > 0) {
        const point = intersects[0].point;
        for (let i = 0; i < N; i++) {
          const dx = neuronPositions[i*3] - point.x;
          const dy = neuronPositions[i*3+1] - point.y;
          const dz = neuronPositions[i*3+2] - point.z;
          const distSq = dx*dx + dy*dy + dz*dz;
          if (distSq < 4) {
            stimulus[i] = (1 - Math.sqrt(distSq) / 2) * 0.5;
          }
        }
      }

      worker.postMessage({
        action: "update",
        data: { stimulus },
        time: performance.now()
      }, [stimulus.buffer]);

      // We need to re-create the buffer since it was transferred
      stimulusBuffer.current = new Float32Array(N);
    };

    requestUpdate();

    // --- Animation Loop ---
    let animationId: number;
    const animate = () => {
      animationId = requestAnimationFrame(animate);

      // Slow rotation
      mesh.rotation.y += 0.002;
      mesh.rotation.z += 0.001;

      renderer.render(scene, camera);
    };
    animate();
    setIsLoaded(true);

    // --- Event Listeners ---
    const handleResize = () => {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };

    const handleMouseMove = (e: MouseEvent) => {
      mouseRef.current.x = (e.clientX / window.innerWidth) * 2 - 1;
      mouseRef.current.y = -(e.clientY / window.innerHeight) * 2 + 1;
    };

    window.addEventListener("resize", handleResize);
    window.addEventListener("mousemove", handleMouseMove);

    return () => {
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMouseMove);
      cancelAnimationFrame(animationId);
      worker.terminate();
      renderer.dispose();
    };
  }, []);

  const changeState = (state: BrainState) => {
    setBrainState(state);
    workerRef.current?.postMessage({ action: "setState", data: { state } });
  };

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-[#05050a] overflow-hidden">
      <canvas ref={canvasRef} className="block w-full h-full" />

      <AnimatePresence>
        {!isLoaded && (
          <motion.div 
            exit={{ opacity: 0 }}
            className="absolute inset-0 flex items-center justify-center bg-black z-50"
          >
            <div className="flex flex-col items-center space-y-4">
              <Brain className="w-12 h-12 text-purple-500 animate-pulse" />
              <p className="text-purple-400 font-mono text-sm tracking-widest">INITIALIZING SYNAPSES...</p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Interface */}
      <div className="absolute top-10 left-1/2 -translate-x-1/2 flex items-center space-x-2 p-2 rounded-full bg-white/5 backdrop-blur-xl border border-white/10">
        {[
          { id: "DEFAULT", icon: Activity, label: "Balanced" },
          { id: "FOCUS", icon: Zap, label: "Focus" },
          { id: "SLEEP", icon: Moon, label: "Deep Sleep" },
          { id: "CREATIVE", icon: Lightbulb, label: "Creative Burst" }
        ].map((s) => (
          <button
            key={s.id}
            onClick={() => changeState(s.id as BrainState)}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-full transition-all duration-500 ${
              brainState === s.id 
                ? "bg-purple-600 text-white shadow-[0_0_20px_rgba(147,51,234,0.5)]" 
                : "text-gray-400 hover:bg-white/10 hover:text-white"
            }`}
          >
            <s.icon size={16} />
            <span className="text-xs font-bold tracking-wider uppercase">{s.label}</span>
          </button>
        ))}
      </div>

      {/* Info HUD */}
      <div className="absolute bottom-10 right-10 p-6 rounded-2xl bg-black/40 backdrop-blur-md border border-white/10 font-mono text-[10px] text-gray-500 pointer-events-none">
        <div className="flex flex-col space-y-1">
          <div className="flex justify-between space-x-8">
            <span>NEURON COUNT</span>
            <span className="text-purple-400">2,000 LIF NODES</span>
          </div>
          <div className="flex justify-between space-x-8">
            <span>SYNAPTIC DENSITY</span>
            <span className="text-purple-400">3.4% SPARSE</span>
          </div>
          <div className="flex justify-between space-x-8">
            <span>CURRENT MODE</span>
            <span className="text-purple-400 uppercase">{brainState}</span>
          </div>
          <div className="mt-4 pt-2 border-t border-white/10">
            <span>MOVE POINTER TO STIMULATE REGIONS</span>
          </div>
        </div>
      </div>

      {/* Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.6)_100%)]" />
    </div>
  );
};

export default NeuralFirestorm;

import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
