import React, { useEffect, useRef, useState } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { Atom, Zap, Info, Activity, Shield } from "lucide-react";

// --- Shaders ---

const foamVertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const foamFragmentShader = `
  uniform float uTime;
  uniform vec2 uRes;
  uniform vec4 uParticles[10]; // x, y, life, pairId
  varying vec2 vUv;

  // Simplex 3D Noise by Ian McEwan
  vec4 permute(vec4 x){return mod(((x*34.0)+1.0)*x, 289.0);}
  vec4 taylorInvSqrt(vec4 r){return 1.79284291400159 - 0.85373472095314 * r;}
  float snoise(vec3 v){ 
    const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
    const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);
    vec3 i  = floor(v + dot(v, C.yyy) );
    vec3 x0 =   v - i + dot(i, C.xxx) ;
    vec3 g = step(x0.yzx, x0.xyz);
    vec3 l = 1.0 - g;
    vec3 i1 = min( g.xyz, l.zxy );
    vec3 i2 = max( g.xyz, l.zxy );
    vec3 x1 = x0 - i1 + 1.0 * C.xxx;
    vec3 x2 = x0 - i2 + 2.0 * C.xxx;
    vec3 x3 = x0 - 1.0 + 3.0 * C.xxx;
    i = mod(i, 289.0 ); 
    vec4 p = permute( permute( permute( 
               i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
             + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
             + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));
    float n_ = 1.0/7.0;
    vec3  ns = n_ * D.wyz - D.xzx;
    vec4 j = p - 49.0 * floor(p * ns.z *ns.z);
    vec4 x_ = floor(j * ns.z);
    vec4 y_ = floor(j - 7.0 * x_ );
    vec4 x = x_ *ns.x + ns.yyyy;
    vec4 y = y_ *ns.x + ns.yyyy;
    vec4 h = 1.0 - abs(x) - abs(y);
    vec4 b0 = vec4( x.xy, y.xy );
    vec4 b1 = vec4( x.zw, y.zw );
    vec4 s0 = floor(b0)*2.0 + 1.0;
    vec4 s1 = floor(b1)*2.0 + 1.0;
    vec4 sh = -step(h, vec4(0.0));
    vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
    vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;
    vec3 p0 = vec3(a0.xy,h.x);
    vec3 p1 = vec3(a0.zw,h.y);
    vec3 p2 = vec3(a1.xy,h.z);
    vec3 p3 = vec3(a1.zw,h.w);
    vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
    p0 *= norm.x; p1 *= norm.y; p2 *= norm.z; p3 *= norm.w;
    vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
    m = m * m;
    return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                dot(p2,x2), dot(p3,x3) ) );
  }

  // Smooth Minimum for metaballs
  float smin(float a, float b, float k) {
    float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
    return mix(b, a, h) - k * h * (1.0 - h);
  }

  void main() {
    vec2 uv = vUv * 2.0 - 1.0;
    uv.x *= uRes.x / uRes.y;

    // 1. Layered Noise Field
    float h = 0.0;
    h += snoise(vec3(uv * 1.5, uTime * 0.1)) * 1.0;
    h += snoise(vec3(uv * 3.0, uTime * 0.2)) * 0.5;
    h += snoise(vec3(uv * 6.0, -uTime * 0.3)) * 0.25;

    // 2. Metaball Blobs
    float blobs = 100.0;
    for(int i = 0; i < 4; i++) {
        float t = uTime * 0.5 + float(i) * 10.0;
        vec2 p = vec2(sin(t * 0.7), cos(t * 0.8)) * 1.5;
        blobs = smin(blobs, length(uv - p), 0.8);
    }
    h = smin(h, -blobs * 2.0, 0.5);

    // 3. Lighting & Normals
    vec3 color = vec3(0.019, 0.019, 0.031); // Background #050508
    vec3 foamColor = vec3(0.039, 0.101, 0.121); // #0a1a1f
    vec3 highlightColor = vec3(0.78, 0.85, 0.88); // #c8d8e0

    // Fake normals
    float dx = 0.01;
    float hx = snoise(vec3((vUv + vec2(dx, 0.0)) * 2.0, uTime * 0.1));
    float hy = snoise(vec3((vUv + vec2(0.0, dx)) * 2.0, uTime * 0.1));
    vec3 normal = normalize(vec3(h - hx, h - hy, dx));

    float diff = max(0.0, dot(normal, normalize(vec3(1.0, 1.0, 2.0))));
    float spec = pow(diff, 16.0);

    color = mix(color, foamColor, clamp(h * 0.5 + 0.5, 0.0, 1.0));
    color += spec * highlightColor * 0.4;

    // 4. Virtual Particles
    for(int i = 0; i < 10; i++) {
        vec2 pPos = uParticles[i].xy;
        float pLife = uParticles[i].z;
        if(pLife > 0.0) {
            float d = length(uv - pPos);
            float glow = exp(-d * 40.0) * pLife;
            color += vec3(glow);
        }
    }

    gl_FragColor = vec4(color, 1.0);
  }
`;

// --- Particle Logic ---

interface VirtualParticle {
  id: number;
  pairId: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
}

// --- Component ---

const QuantumFoam: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [particles, setParticles] = useState<VirtualParticle[]>([]);
  const particlesRef = useRef<VirtualParticle[]>([]);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);

    const uniforms = {
      uTime: { value: 0 },
      uRes: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
      uParticles: { value: new Float32Array(40).fill(0) } // [x,y,life,0] * 10
    };

    const geometry = new THREE.PlaneGeometry(2, 2);
    const material = new THREE.ShaderMaterial({
      vertexShader: foamVertexShader,
      fragmentShader: foamFragmentShader,
      uniforms
    });
    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);

    // Particle Spawning Loop
    const spawnPair = () => {
      if (particlesRef.current.length >= 10) return;

      const px = (Math.random() - 0.5) * 2;
      const py = (Math.random() - 0.5) * 2;
      const angle = Math.random() * Math.PI * 2;
      const speed = 0.01 + Math.random() * 0.02;
      const life = 1.0 + Math.random() * 0.5;
      const pairId = Math.random();

      const p1: VirtualParticle = {
        id: Math.random(), pairId, x: px, y: py, 
        vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed, 
        life, maxLife: life 
      };
      const p2: VirtualParticle = {
        id: Math.random(), pairId, x: px, y: py, 
        vx: -Math.cos(angle) * speed, vy: -Math.sin(angle) * speed, 
        life, maxLife: life 
      };

      particlesRef.current.push(p1, p2);
    };

    const spawnInterval = setInterval(spawnPair, 1000);

    // Animation Loop
    let animationId: number;
    const animate = (time: number) => {
      animationId = requestAnimationFrame(animate);

      // Update Particles
      for (let i = particlesRef.current.length - 1; i >= 0; i--) {
        const p = particlesRef.current[i];
        p.life -= 0.02;
        if (p.life <= 0) {
          particlesRef.current.splice(i, 1);
          continue;
        }

        // Appear -> Separate -> Converge -> Annihilate
        const t = 1.0 - (p.life / p.maxLife);
        if (t < 0.5) {
          // Separate
          p.x += p.vx;
          p.y += p.vy;
        } else {
          // Converge
          p.x -= p.vx * 1.2;
          p.y -= p.vy * 1.2;
        }
      }

      // Sync uniforms
      const pData = new Float32Array(40).fill(0);
      particlesRef.current.slice(0, 10).forEach((p, i) => {
        pData[i * 4] = p.x;
        pData[i * 4 + 1] = p.y;
        pData[i * 4 + 2] = Math.max(0, p.life);
        pData[i * 4 + 3] = p.pairId;
      });
      uniforms.uParticles.value = pData;
      uniforms.uTime.value = time * 0.001;

      renderer.render(scene, camera);
    };
    animate(0);

    return () => {
      clearInterval(spawnInterval);
      cancelAnimationFrame(animationId);
      renderer.dispose();
    };
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-[#050508] overflow-hidden">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Atmospheric HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-xl font-light text-white/20 tracking-[0.5em] uppercase">
          Quantum Foam Monitor
        </h1>
        <div className="flex items-center space-x-3 mt-2">
           <Activity size={12} className="text-cyan-500/50 animate-pulse" />
           <span className="text-[10px] text-white/10 font-mono tracking-widest uppercase">
             Non-Deterministic Fluctuations Active
           </span>
        </div>
      </div>

      <div className="absolute bottom-10 right-10 z-40 text-[9px] text-white/10 uppercase tracking-[0.3em] max-w-xs text-right leading-relaxed italic">
        "Space is not empty, but a boiling sea of virtual particles appearing and disappearing at the Planck scale."
      </div>

      <div className="absolute bottom-10 left-10 z-40 flex items-center space-x-4 p-2 rounded-xl bg-white/5 border border-white/10 backdrop-blur-xl opacity-30 hover:opacity-100 transition-opacity">
        <div className="p-2 text-cyan-400">
           <Atom size={16} />
        </div>
        <span className="text-[9px] text-white/60 font-mono tracking-widest uppercase pr-4">
          Sub-Perceptual Rendering Engine
        </span>
      </div>

      {/* Screen Effects */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_200px_rgba(0,0,0,1)]" />
      <div className="absolute inset-0 pointer-events-none bg-gradient-to-tr from-cyan-900/5 to-transparent" />
    </div>
  );
};

