import React, { useEffect, useRef, useState, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Mic, MicOff, Download, Activity, Music, Info, Trash2, Moon, Sun } from "lucide-react";

interface SilenceEvent {
  id: string;
  startTime: number;
  duration: number;
  context: 'post-loud' | 'post-soft' | 'mid-phrase' | 'between-phrases';
  freq: 'high' | 'low';
  intensity: number;
}

const SilenceArchitecture: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isListening, setIsListening] = useState(false);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const [events, setEvents] = useState<SilenceEvent[]>([]);
  const [threshold, setThreshold] = useState(0.01);

  const audioCtxRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const silenceRef = useRef<{ active: boolean, start: number, preRms: number, preFreq: number }>({
    active: false, start: 0, preRms: 0, preFreq: 0
  });

  const startListening = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ctx = new AudioContext();
      const source = ctx.createMediaStreamSource(stream);
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);

      audioCtxRef.current = ctx;
      analyserRef.current = analyser;
      setIsListening(true);

      processAudio();
    } catch (err) {
      console.error("Mic access denied", err);
    }
  };

  const processAudio = () => {
    if (!analyserRef.current || !isListening) return;

    const dataArray = new Float32Array(analyserRef.current.fftSize);
    analyserRef.current.getFloatTimeDomainData(dataArray);

    // Calculate RMS
    let sum = 0;
    for (let i = 0; i < dataArray.length; i++) sum += dataArray[i] * dataArray[i];
    const rms = Math.sqrt(sum / dataArray.length);

    // Frequency Analysis
    const freqArray = new Uint8Array(analyserRef.current.frequencyBinCount);
    analyserRef.current.getByteFrequencyData(freqArray);
    let avgFreq = 0;
    for (let i = 0; i < freqArray.length; i++) avgFreq += freqArray[i];
    avgFreq /= freqArray.length;

    const now = Date.now();
    const isSilent = rms < threshold;

    if (isSilent && !silenceRef.current.active) {
      // Start Silence
      silenceRef.current = { active: true, start: now, preRms: rms, preFreq: avgFreq };
    } else if (!isSilent && silenceRef.current.active) {
      // End Silence
      const duration = now - silenceRef.current.start;
      if (duration >= 80) {
        const event: SilenceEvent = {
          id: Math.random().toString(),
          startTime: (silenceRef.current.start - (audioCtxRef.current?.baseLatency || 0)) % 60000, // Wrapped timeline
          duration,
          context: silenceRef.current.preRms > 0.05 ? 'post-loud' : 'post-soft',
          freq: silenceRef.current.preFreq > 100 ? 'high' : 'low',
          intensity: silenceRef.current.preRms
        };
        setEvents(prev => [...prev, event]);
      }
      silenceRef.current.active = false;
    }

    requestAnimationFrame(processAudio);
  };

  useEffect(() => {
    if (isListening) processAudio();
  }, [isListening]);

  // --- Rendering ---
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    ctx.fillStyle = theme === 'dark' ? "#050508" : "#f0f0f0";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const width = canvas.width;
    const height = canvas.height;

    events.forEach(e => {
      const x = (e.startTime / 60000) * width;
      const y = height / 2;
      const size = Math.log(e.duration) * 10;

      ctx.globalAlpha = 0.8;
      ctx.fillStyle = e.freq === 'high' ? "#4fd1c5" : "#f6ad55";
      ctx.shadowBlur = e.duration > 1000 ? 20 : 0;
      ctx.shadowColor = ctx.fillStyle as string;

      if (e.context === 'post-loud') {
        // Sharp Angular
        ctx.beginPath();
        ctx.moveTo(x, y - size);
        ctx.lineTo(x + size, y + size);
        ctx.lineTo(x - size, y + size);
        ctx.closePath();
        ctx.fill();
      } else {
        // Curved Organic
        ctx.beginPath();
        ctx.arc(x, y, size, 0, Math.PI * 2);
        ctx.fill();
      }
    });
  }, [events, theme]);

  const downloadScore = () => {
    const link = document.createElement('a');
    link.download = 'silence_score.png';
    link.href = canvasRef.current!.toDataURL();
    link.click();
  };

  return (
    <div className={`relative w-full h-screen ${theme === 'dark' ? 'bg-[#050508]' : 'bg-[#f0f0f0]'} overflow-hidden transition-colors duration-700`}>
      <canvas 
        ref={canvasRef} 
        width={window.innerWidth * 2} 
        height={window.innerHeight * 2}
        className="block w-full h-full opacity-90"
      />

      {/* Atmospheric HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className={`text-xl font-light tracking-[0.5em] uppercase ${theme === 'dark' ? 'text-white/20' : 'text-black/40'}`}>
          Silence Architecture
        </h1>
        <div className="flex items-center space-x-3 mt-2">
           <Music size={12} className="text-blue-500/50 animate-pulse" />
           <span className={`text-[10px] font-mono tracking-widest uppercase ${theme === 'dark' ? 'text-white/10' : 'text-black/20'}`}>
             Translating Absence into Form
           </span>
        </div>
      </div>

      {/* Controls */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 z-40 flex items-center space-x-6 p-4 rounded-3xl bg-white/5 border border-white/10 backdrop-blur-2xl">
        <button 
          onClick={isListening ? () => setIsListening(false) : startListening}
          className={`flex items-center space-x-3 px-8 py-3 rounded-2xl transition-all ${isListening ? "bg-red-500 text-white" : "bg-blue-600 text-white"}`}
        >
          {isListening ? <MicOff size={16} /> : <Mic size={16} />}
          <span className="text-[10px] font-bold uppercase tracking-widest">{isListening ? "Pause Analysis" : "Begin Capture"}</span>
        </button>

        <div className="w-px h-6 bg-white/10" />

        <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="p-3 text-white/40 hover:text-white transition-colors">
          {theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
        </button>

        <button onClick={downloadScore} className="p-3 text-white/40 hover:text-white transition-colors">
          <Download size={18} />
        </button>

        <button onClick={() => setEvents([])} className="p-3 text-white/40 hover:text-red-400 transition-colors">
          <Trash2 size={18} />
        </button>
      </div>

      {/* Metrics */}
      <div className="absolute bottom-10 right-10 z-40 text-right space-y-4">
        <div className="flex flex-col">
            <span className={`text-[9px] uppercase tracking-widest ${theme === 'dark' ? 'text-white/10' : 'text-black/20'}`}>Detected Voids</span>
            <span className={`text-4xl font-light ${theme === 'dark' ? 'text-white' : 'text-black'}`}>{events.length}</span>
        </div>
        <div className={`text-[9px] uppercase tracking-[0.3em] max-w-xs italic leading-relaxed ${theme === 'dark' ? 'text-white/10' : 'text-black/20'}`}>
            "Silence is the architecture of the score."
        </div>
      </div>

      {/* Screen Effects */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_200px_rgba(0,0,0,0.5)]" />
    </div>
  );
};

