import React, { useEffect, useRef, useState, useMemo } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { Sun, Cloud, MapPin, Clock, Info, Compass } from "lucide-react";
import { getSolarElevation, kelvinToRGB } from "./solarCalc";

// --- Shader ---

const skyVertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const skyFragmentShader = `
  uniform vec3 uBaseColor;
  uniform float uElevation;
  varying vec2 vUv;

  void main() {
    vec3 col = uBaseColor;

    // 1. Vertical Gradient
    float topShift = smoothstep(0.0, 1.0, vUv.y);
    vec3 skyCol = mix(col * 0.8, col * 1.1, topShift);

    // 2. Atmospheric Scattering (Haze Band)
    // Strongest at low elevations (0 to 15 degrees)
    float hazeIntensity = clamp((15.0 - abs(uElevation)) / 15.0, 0.0, 1.0);
    if (uElevation < -6.0) hazeIntensity = 0.0; // Fade at night

    float haze = exp(-abs(vUv.y - 0.2) * 8.0) * hazeIntensity * 0.3;
    vec3 hazeCol = mix(skyCol, vec3(1.0, 0.6, 0.3), haze); // Warm scattering

    col = mix(skyCol, hazeCol, haze);

    // 3. Night Fade
    float nightMask = smoothstep(-12.0, -2.0, uElevation);
    col *= nightMask;

    gl_FragColor = vec4(col, 1.0);
  }
`;

// --- Component ---

const SkyChronometer: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loc, setLoc] = useState({ lat: 40.7128, lng: -74.0060 }); // Default NYC
  const [elevation, setElevation] = useState(0);
  const [kelvin, setKelvin] = useState(6500);
  const [isLive, setIsLive] = useState(false);

  // Three.js Refs
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const uniformsRef = useRef<any>(null);

  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        setLoc({ lat: pos.coords.latitude, lng: pos.coords.longitude });
        setIsLive(true);
      });
    }
  }, []);

  useEffect(() => {
    if (!canvasRef.current) return;

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);

    const uniforms = {
      uBaseColor: { value: new THREE.Color(1, 1, 1) },
      uElevation: { value: 0 },
    };
    uniformsRef.current = uniforms;

    const material = new THREE.ShaderMaterial({
      vertexShader: skyVertexShader,
      fragmentShader: skyFragmentShader,
      uniforms
    });
    const mesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), material);
    scene.add(mesh);

    // Update Loop
    const update = () => {
      const el = getSolarElevation(loc.lat, loc.lng);
      setElevation(el);

      // Elevation to Kelvin
      let k = 6500;
      if (el < -18) k = 0;
      else if (el < 0) k = 1000 + (el + 18) * (1000 / 18);
      else if (el < 60) k = 2000 + (el / 60) * 4500;
      setKelvin(k);

      const rgb = kelvinToRGB(k);
      uniforms.uBaseColor.value.setRGB(rgb[0], rgb[1], rgb[2]);
      uniforms.uElevation.value = el;

      renderer.render(scene, camera);
      requestAnimationFrame(update);
    };

    const animId = requestAnimationFrame(update);

    const handleResize = () => {
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      cancelAnimationFrame(animId);
      renderer.dispose();
    };
  }, [loc]);

  return (
    <div className="relative w-full h-screen bg-black overflow-hidden font-mono">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Atmospheric HUD */}
      <div className="absolute bottom-12 left-12 z-40 p-8 rounded-3xl bg-black/20 backdrop-blur-2xl border border-white/5 text-white/40 pointer-events-none">
        <div className="space-y-4">
          <div className="flex flex-col">
            <span className="text-[10px] tracking-[0.3em] uppercase opacity-50">Solar Temperature</span>
            <span className="text-3xl font-light text-white tracking-tighter">
              {kelvin > 0 ? `${Math.round(kelvin)}K` : "NOX"}
            </span>
          </div>

          <div className="grid grid-cols-2 gap-8 pt-4 border-t border-white/5">
            <div className="flex flex-col">
              <span className="text-[9px] tracking-widest uppercase opacity-40">Elevation</span>
              <span className="text-sm text-white/80">{elevation.toFixed(2)}°</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[9px] tracking-widest uppercase opacity-40">Position</span>
              <span className="text-sm text-white/80">{loc.lat.toFixed(2)}°N</span>
            </div>
          </div>

          <div className="flex items-center space-x-3 pt-2">
            <div className={`w-1.5 h-1.5 rounded-full ${isLive ? "bg-green-500" : "bg-orange-500"} animate-pulse`} />
            <span className="text-[8px] tracking-[0.2em] uppercase">
              {isLive ? "Live Geolocation Active" : "Using Region Defaults"}
            </span>
          </div>
        </div>
      </div>

      {/* Clock HUD */}
      <div className="absolute top-10 right-10 z-40 text-right">
        <div className="text-white/20 text-[10px] tracking-[0.4em] uppercase mb-1">Local Chronometer</div>
        <div className="text-white/60 text-xl font-light">
          {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
        </div>
      </div>

      <div className="absolute top-10 left-10 z-40">
        <h1 className="text-xl font-light text-white/30 tracking-[0.5em] uppercase flex items-center gap-3">
            <Compass size={18} className="opacity-50" />
            Sky Chronometer
        </h1>
      </div>

      {/* Aesthetic Overlays */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_150px_rgba(0,0,0,0.5)]" />
      <div className="absolute inset-0 pointer-events-none opacity-10 bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]" />
    </div>
  );
};

