import React, { useEffect, useRef, useState } from "react";
import * as THREE from "three";
import { motion, AnimatePresence } from "framer-motion";
import { BrainCircuit, Zap, MousePointer2, Info, Layout } from "lucide-react";

// --- Shaders ---

const agentUpdateShader = `
  uniform sampler2D uAgentData;
  uniform sampler2D uTrailMap;
  uniform vec2 uRes;
  uniform float uTime;
  uniform float uSensorAngle;
  uniform float uSensorDist;
  uniform float uTurnSpeed;
  uniform float uMoveSpeed;

  varying vec2 vUv;

  float hash(float n) { return fract(sin(n) * 43758.5453123); }

  void main() {
    vec4 data = texture2D(uAgentData, vUv);
    vec2 pos = data.xy;
    float angle = data.z;

    // Sensing
    float sensorAngle = uSensorAngle;
    float sensorDist = uSensorDist;

    vec2 dirF = vec2(cos(angle), sin(angle));
    vec2 dirL = vec2(cos(angle - sensorAngle), sin(angle - sensorAngle));
    vec2 dirR = vec2(cos(angle + sensorAngle), sin(angle + sensorAngle));

    float sF = texture2D(uTrailMap, pos + dirF * sensorDist).r;
    float sL = texture2D(uTrailMap, pos + dirL * sensorDist).r;
    float sR = texture2D(uTrailMap, pos + dirR * sensorDist).r;

    float rand = hash(vUv.x + vUv.y + uTime);

    if (sF > sL && sF > sR) {
        // Stay same
    } else if (sF < sL && sF < sR) {
        angle += (rand - 0.5) * 2.0 * uTurnSpeed;
    } else if (sL > sR) {
        angle -= uTurnSpeed;
    } else if (sR > sL) {
        angle += uTurnSpeed;
    }

    // Move
    pos += vec2(cos(angle), sin(angle)) * uMoveSpeed;

    // Bounce
    if (pos.x < 0.0 || pos.x > 1.0) angle = 3.14159 - angle;
    if (pos.y < 0.0 || pos.y > 1.0) angle = -angle;
    pos = clamp(pos, 0.0, 1.0);

    gl_FragColor = vec4(pos, angle, 1.0);
  }
`;

const trailUpdateShader = `
  uniform sampler2D uTrailMap;
  uniform vec2 uRes;
  uniform float uDecay;
  uniform float uDiffuse;
  varying vec2 vUv;

  void main() {
    vec2 texel = 1.0 / uRes;
    float avg = 0.0;

    // 3x3 Box Blur
    for (int x = -1; x <= 1; x++) {
      for (int y = -1; y <= 1; y++) {
        avg += texture2D(uTrailMap, vUv + vec2(float(x), float(y)) * texel).r;
      }
    }
    avg /= 9.0;

    float val = texture2D(uTrailMap, vUv).r;
    val = mix(val, avg, uDiffuse);
    val *= uDecay;

    gl_FragColor = vec4(vec3(val), 1.0);
  }
`;

const renderShader = `
  uniform sampler2D uTrailMap;
  varying vec2 vUv;
  void main() {
    float val = texture2D(uTrailMap, vUv).r;

    // Color Mapping: Black -> Orange -> White
    vec3 col = mix(vec3(0.01), vec3(0.9, 0.4, 0.1), clamp(val * 5.0, 0.0, 1.0));
    col = mix(col, vec3(1.0, 0.9, 0.6), clamp((val - 0.2) * 2.0, 0.0, 1.0));

    gl_FragColor = vec4(col, 1.0);
  }
`;

// --- Component ---

const SlimeMould: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [agentCount] = useState(100000);

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    const width = 1024;
    const height = 1024;

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    const renderer = new THREE.WebGLRenderer({ canvas: canvasRef.current, antialias: false });
    renderer.setSize(window.innerWidth, window.innerHeight);

    // --- Textures ---
    const options = { type: THREE.FloatType, minFilter: THREE.NearestFilter, magFilter: THREE.NearestFilter };

    // Agent Data [x, y, angle, 1]
    const size = 512; // 262,144 agents
    const initialData = new Float32Array(size * size * 4);
    for(let i=0; i<size*size; i++) {
        initialData[i*4] = Math.random();
        initialData[i*4+1] = Math.random();
        initialData[i*4+2] = Math.random() * Math.PI * 2;
        initialData[i*4+3] = 1.0;
    }
    const agentTex1 = new THREE.DataTexture(initialData, size, size, THREE.RGBAFormat, THREE.FloatType);
    agentTex1.needsUpdate = true;

    let agentRT1 = new THREE.WebGLRenderTarget(size, size, options);
    let agentRT2 = new THREE.WebGLRenderTarget(size, size, options);

    // Trail Map
    let trailRT1 = new THREE.WebGLRenderTarget(width, height, options);
    let trailRT2 = new THREE.WebGLRenderTarget(width, height, options);

    // --- Materials ---
    const agentUpdateMat = new THREE.ShaderMaterial({
      uniforms: {
        uAgentData: { value: agentTex1 },
        uTrailMap: { value: trailRT1.texture },
        uRes: { value: new THREE.Vector2(size, size) },
        uTime: { value: 0 },
        uSensorAngle: { value: 0.5 },
        uSensorDist: { value: 0.015 },
        uTurnSpeed: { value: 0.15 },
        uMoveSpeed: { value: 0.002 }
      },
      vertexShader: `varying vec2 vUv; void main() { vUv = uv; gl_Position = vec4(position, 1.0); }`,
      fragmentShader: agentUpdateShader
    });

    const trailUpdateMat = new THREE.ShaderMaterial({
      uniforms: {
        uTrailMap: { value: trailRT1.texture },
        uRes: { value: new THREE.Vector2(width, height) },
        uDecay: { value: 0.94 },
        uDiffuse: { value: 0.2 }
      },
      vertexShader: `varying vec2 vUv; void main() { vUv = uv; gl_Position = vec4(position, 1.0); }`,
      fragmentShader: trailUpdateShader
    });

    const depositMat = new THREE.PointsMaterial({ size: 1, color: 0xffffff, blending: THREE.AdditiveBlending, transparent: true, opacity: 0.5 });
    const depositGeo = new THREE.BufferGeometry();
    const posAttr = new THREE.BufferAttribute(new Float32Array(size * size * 3), 3);
    const uvAttr = new THREE.BufferAttribute(new Float32Array(size * size * 2), 2);
    for(let i=0; i<size*size; i++) {
        uvAttr.setXY(i, (i % size) / size, Math.floor(i / size) / size);
    }
    depositGeo.setAttribute('position', posAttr);
    depositGeo.setAttribute('uv_agent', uvAttr);

    const depositShaderMat = new THREE.ShaderMaterial({
        uniforms: { uAgentData: { value: agentRT1.texture } },
        vertexShader: `
            uniform sampler2D uAgentData;
            attribute vec2 uv_agent;
            void main() {
                vec4 data = texture2D(uAgentData, uv_agent);
                gl_Position = vec4(data.xy * 2.0 - 1.0, 0.0, 1.0);
                gl_PointSize = 1.0;
            }
        `,
        fragmentShader: `void main() { gl_FragColor = vec4(0.5, 0.0, 0.0, 1.0); }`,
        blending: THREE.AdditiveBlending,
        transparent: true
    });
    const depositPoints = new THREE.Points(depositGeo, depositShaderMat);

    const renderMat = new THREE.ShaderMaterial({
      uniforms: { uTrailMap: { value: trailRT1.texture } },
      vertexShader: `varying vec2 vUv; void main() { vUv = uv; gl_Position = vec4(position, 1.0); }`,
      fragmentShader: renderShader
    });

    const fullScreenQuad = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), renderMat);
    const orthoScene = new THREE.Scene();
    orthoScene.add(fullScreenQuad);

    // --- Animation Loop ---
    let frame = 0;
    const animate = (time: number) => {
      frame++;
      requestAnimationFrame(animate);

      // 1. Update Agents
      agentUpdateMat.uniforms.uAgentData.value = frame === 1 ? agentTex1 : agentRT1.texture;
      agentUpdateMat.uniforms.uTrailMap.value = trailRT1.texture;
      agentUpdateMat.uniforms.uTime.value = time * 0.001;
      renderer.setRenderTarget(agentRT2);
      renderer.render(orthoScene, camera, { material: agentUpdateMat } as any);
      [agentRT1, agentRT2] = [agentRT2, agentRT1];

      // 2. Deposit
      depositShaderMat.uniforms.uAgentData.value = agentRT1.texture;
      renderer.setRenderTarget(trailRT1);
      renderer.autoClear = false;
      renderer.render(depositPoints, camera);
      renderer.autoClear = true;

      // 3. Diffuse/Decay
      trailUpdateMat.uniforms.uTrailMap.value = trailRT1.texture;
      renderer.setRenderTarget(trailRT2);
      renderer.render(orthoScene, camera, { material: trailUpdateMat } as any);
      [trailRT1, trailRT2] = [trailRT2, trailRT1];

      // 4. Render to screen
      renderMat.uniforms.uTrailMap.value = trailRT1.texture;
      renderer.setRenderTarget(null);
      renderer.render(orthoScene, camera);
    };
    animate(0);

    const handleResize = () => {
      renderer.setSize(window.innerWidth, window.innerHeight);
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      renderer.dispose();
    };
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-screen bg-black overflow-hidden">
      <canvas ref={canvasRef} className="block w-full h-full" />

      {/* Atmospheric HUD */}
      <div className="absolute top-10 left-10 z-40 pointer-events-none">
        <h1 className="text-xl font-light text-white/40 tracking-[0.5em] uppercase">
          Physarum Intelligence
        </h1>
        <div className="flex items-center space-x-3 mt-2">
           <BrainCircuit size={12} className="text-amber-500/50 animate-pulse" />
           <span className="text-[10px] text-white/10 font-mono tracking-widest uppercase">
             Simulating 262,144 Biological Agents
           </span>
        </div>
      </div>

      <div className="absolute bottom-10 left-10 z-40 p-6 rounded-2xl bg-black/40 backdrop-blur-md border border-white/10 font-mono text-[10px] text-gray-500 pointer-events-none">
        <div className="space-y-2">
          <div className="flex justify-between space-x-12">
            <span>NETWORK EFFICIENCY</span>
            <span className="text-amber-500">OPTIMIZING...</span>
